      function CF_AWARD_DESCRFORMULA return Char is

V_AWARD_FLAG PEN_DECISION_INSTANCE.AWARD_TYPE_FLAG%TYPE;
V_PROMPT     VARCHAR2(50);

Cursor cur_award_prompt Is
SELECT A.AWARD_TYPE_FLAG
FROM PEN_DECISION_INSTANCE A										 
WHERE A.DEC_INCR_SEQ_NO =:P_DECISION_NO
AND A.DT_DEC_UNIT_CODE=:P_DT_DEC_UNIT_CODE_DIR
AND A.DT_DECISION_YEAR=:P_DT_DECISION_YEAR_DIR
AND A.DT_DOCUMENT_TYPE_DEC_CODE='1';

begin
 
 OPEN cur_award_prompt;
   FETCH cur_award_prompt 
   INTO V_AWARD_FLAG;
 CLOSE cur_award_prompt;
 
 IF V_AWARD_FLAG ='0' THEN
 	  V_PROMPT:='απονομή';
 ELSE 	
 	  V_PROMPT:='τροποποίηση της απόφασης απονομής';
	END IF;
 
 RETURN V_PROMPT;
 
end;

      function CF_AWARD_FLGFormula return Char is

V_AWARD_FLAG PEN_DECISION_INSTANCE.AWARD_TYPE_FLAG%TYPE;

Cursor cur_award_prompt Is
SELECT A.AWARD_TYPE_FLAG
FROM PEN_DECISION_INSTANCE A										 
WHERE A.DT_DOCUMENT_TYPE_DEC_CODE='1'
AND A.DT_DEC_UNIT_CODE=:P_DT_DEC_UNIT_CODE
AND A.DT_DECISION_YEAR=:P_DT_DECISION_YEAR
AND A.DEC_INCR_SEQ_NO =:P_DECISION_NO;

begin
 
 OPEN cur_award_prompt;
   FETCH cur_award_prompt 
   INTO V_AWARD_FLAG;
 CLOSE cur_award_prompt;
 
 RETURN V_AWARD_FLAG;
 
end;

      function CF_00420Formula return Date is
v_calc_begin_date_varchar VARCHAR2(10);
V_DATE DATE;

	CURSOR Cur_is_new_assignee IS
	SELECT 1
	FROM PEN_DECISION_INSTANCE_DEATH A
	WHERE A.ACC_ACCOUNT_NO = :P_Acc_Account_No
	AND STATUS = '1'
	AND A.NEW_OLD_DEC IN ('NEW-INS','NEW');
	
  CURSOR Cur_death_start_date IS
	SELECT A.start_date
	FROM PEN_ACCOUNT A
	WHERE A.ACCOUNT_NO = :P_Acc_Account_No_Dir;	

	v_is_new_assignee_flg NUMBER:=0;

BEGIN

   OPEN Cur_is_new_assignee;
   FETCH Cur_is_new_assignee
   INTO v_is_new_assignee_flg;
   CLOSE Cur_is_new_assignee;

  v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_Insured_Id_IND,:P_DT_DECISION_YEAR_SR,:P_DT_DEC_UNIT_CODE_SR,:P_DT_INCR_SEC_NO_SR, '1',
			 0,0,'00001','00318','00420');
  	
  	IF v_is_new_assignee_flg = 1 THEN
					OPEN Cur_death_start_date;
				  FETCH Cur_death_start_date
				  INTO V_DATE;
				  CLOSE Cur_death_start_date;
		ELSE
			  V_DATE:= TO_DATE(v_calc_begin_date_varchar,'DD/MM/RRRR'); 
		END IF;
  
  
  
  IF v_calc_begin_date_varchar IS NOT NULL OR v_is_new_assignee_flg = 1  THEN 
    RETURN (V_DATE); 
  ELSE 
   RETURN '';
  END IF;
END;

      FUNCTION CF_PAYMENT_AMOUNTFormula RETURN NUMBER IS

v_calc_begin_date_varchar VARCHAR2(10);
v_calc_begin_date DATE;
V_AMOUNT NUMBER;

	CURSOR Cur_is_new_assignee IS
	SELECT 1
	FROM PEN_DECISION_INSTANCE_DEATH A
	WHERE A.ACC_ACCOUNT_NO = :P_Acc_Account_No
	AND STATUS = '1'
	AND A.NEW_OLD_DEC IN ('NEW-INS','NEW');
		
	CURSOR Cur_death_start_date IS
	SELECT A.start_date
	FROM PEN_ACCOUNT A
	WHERE A.ACCOUNT_NO = :P_Acc_Account_No_Dir;	

	v_is_new_assignee_flg NUMBER:=0;

BEGIN

   OPEN Cur_is_new_assignee;
   FETCH Cur_is_new_assignee
   INTO v_is_new_assignee_flg;
   CLOSE Cur_is_new_assignee;

	  v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_Insured_Id_IND,:P_DT_DECISION_YEAR_SR,:P_DT_DEC_UNIT_CODE_SR,:P_DT_INCR_SEC_NO_SR, '1',
					 0,0,'00001','00318','00420');

		IF v_calc_begin_date_varchar IS NOT NULL THEN
		   v_calc_begin_date := TO_DATE(v_calc_begin_date_varchar,'DD/MM/RRRR');
		END IF;

  	IF v_is_new_assignee_flg = 1 THEN
					OPEN Cur_death_start_date;
				  FETCH Cur_death_start_date
				  INTO v_calc_begin_date;
				  CLOSE Cur_death_start_date;
		END IF;

	V_AMOUNT := Penbat_Payments.Calc_Total_Scale_Raise_Back (NULL
																													 ,NULL
																													 ,v_calc_begin_date
																												 	 ,:P_ACC_START_DATE
																													 ,:P_PENSION_AMOUNT);
  
  RETURN (ROUND(V_AMOUNT,2)+:P_PENSION_AMOUNT); 
  
  
END;

      function CF_PROTOCOL_CASEFormula return Char is
V_STRING VARCHAR2(200);
V_PROTOCOL_NO     PEN_DECISION_INSTANCE.CONVERT_PROTOCOL_NO%TYPE;
V_PROTOCOL_DATE   PEN_DECISION_INSTANCE.CONVERT_PROTOCOL_DATE%TYPE;

begin

  IF :CF_AWARD_FLG!='0' THEN 
	  SELECT A.CONVERT_PROTOCOL_NO ,
		       A.CONVERT_PROTOCOL_DATE
	  INTO V_PROTOCOL_NO,
	       V_PROTOCOL_DATE
		FROM PEN_DECISION_INSTANCE A										 
		WHERE A.DEC_INCR_SEQ_NO =:P_DECISION_NO
		AND A.DT_DEC_UNIT_CODE=:P_DT_DEC_UNIT_CODE_DIR
		AND A.DT_DECISION_YEAR=:P_DT_DECISION_YEAR_DIR
		AND A.DT_DOCUMENT_TYPE_DEC_CODE='1';
 END IF;
	
IF :CF_AWARD_FLG='0' THEN 
	IF :PROTOCOL_NO IS NOT NULL THEN 
     V_STRING := 'τη με αριθμό Πρωτοκόλλου '|| :PEN_APPLICATION_INSTANCES_PROT || ' αίτηση ' ||:CS_3 ||'για σύνταξη λόγω θανάτου ασφ/νου, έχοντας υπόψη:';
 ELSE 
     V_STRING := 'οίκοθεν την περίπτωση ' || :CS_3 || 'για σύνταξη λόγω θανάτου ασφ/νου, έχοντας υπόψη:';
  END IF;    
ELSE
 	IF V_PROTOCOL_NO IS NOT NULL THEN 
     V_STRING := 'τη με αριθμό Πρωτοκόλλου '|| V_PROTOCOL_NO ||'-'||V_PROTOCOL_DATE || ' αίτηση ' ||:CS_3 ||'για σύνταξη λόγω θανάτου ασφ/νου, έχοντας υπόψη:';
 ELSE 
     V_STRING := 'οίκοθεν την περίπτωση ' || :CS_3 || 'για σύνταξη λόγω θανάτου ασφ/νου, έχοντας υπόψη:';
  END IF;    
END IF;
  return (V_STRING);
end;

