Function CF_ANNOUNCEMENTFormula return char Is
V_BRANCH_CODE VARCHAR2(20); V_BRANCH_NAME VARCHAR2(2000);
cursor c1 is SELECT PEN_DEC_FACT_TYPES_INSTANCE.VALUE, DECODE(A.BRANCH_CODE, '09930', 'ΤΜΗΜΑ ΔΙΕΝΕΡΓΕΙΑΣ ΜΕΤΑΒΟΛΩΝ ', A.BRANCH_NAME) BRANCH_NAME FROM PEN_DEC_FACT_TYPES_INSTANCE, COM_ORG_BRANCHES A WHERE PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_INCR_SEQ_NO_SR = :P_DT_INCR_SEC_NO_SR ---I_DEC_INCR_SEQ_NO1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR ---I_DEC_UNIT1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR ---I_DEC_YEAR1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' ---I_DEC_DOC_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.TITLE_CODE = '00172' ---S_SPECIAL_FACT_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.DEC_FACT_TYPE_CODE = '00247' ---S_SPECIAL_FACT_SUBTYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.INS_INSURED_ID = :P_Insured_Id_IND ---I_INSURED_ID1 AND PEN_DEC_FACT_TYPES_INSTANCE.STATUS = '1' AND PEN_DEC_FACT_TYPES_INSTANCE.VALUE = A.BRANCH_CODE UNION SELECT PEN_DEC_FACT_TYPES_INSTANCE.VALUE, DECODE(A.BRANCH_CODE, '09930', 'ΤΜΗΜΑ ΔΙΕΝΕΡΓΕΙΑΣ ΜΕΤΑΒΟΛΩΝ ', A.BRANCH_NAME) BRANCH_NAME FROM PEN_DEC_FACT_TYPES_INSTANCE, COM_ORG_BRANCHES A WHERE PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_INCR_SEQ_NO_SR = :P_DT_INCR_SEC_NO_SR ---I_DEC_INCR_SEQ_NO1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR ---I_DEC_UNIT1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR ---I_DEC_YEAR1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' ---I_DEC_DOC_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.TITLE_CODE = '00069' ---S_SPECIAL_FACT_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.DEC_FACT_TYPE_CODE = '00247' ---S_SPECIAL_FACT_SUBTYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.INS_INSURED_ID = :P_Insured_Id_IND ---I_INSURED_ID1 AND PEN_DEC_FACT_TYPES_INSTANCE.STATUS = '1' AND PEN_DEC_FACT_TYPES_INSTANCE.VALUE = A.BRANCH_CODE UNION SELECT PEN_DEC_FACT_TYPES_INSTANCE.VALUE, DECODE(A.BRANCH_CODE, '09930', 'ΤΜΗΜΑ ΔΙΕΝΕΡΓΕΙΑΣ ΜΕΤΑΒΟΛΩΝ ', A.BRANCH_NAME) BRANCH_NAME FROM PEN_DEC_FACT_TYPES_INSTANCE, COM_ORG_BRANCHES A WHERE PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_INCR_SEQ_NO_SR = :P_DT_INCR_SEC_NO_SR ---I_DEC_INCR_SEQ_NO1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR ---I_DEC_UNIT1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR ---I_DEC_YEAR1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' ---I_DEC_DOC_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.TITLE_CODE = '01069' ---S_SPECIAL_FACT_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.DEC_FACT_TYPE_CODE = '00247' ---S_SPECIAL_FACT_SUBTYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.INS_INSURED_ID = :P_Insured_Id_IND ---I_INSURED_ID1 AND PEN_DEC_FACT_TYPES_INSTANCE.STATUS = '1' AND PEN_DEC_FACT_TYPES_INSTANCE.VALUE = A.BRANCH_CODE UNION SELECT PEN_DEC_FACT_TYPES_INSTANCE.VALUE, DECODE(A.BRANCH_CODE, '09930', 'ΤΜΗΜΑ ΔΙΕΝΕΡΓΕΙΑΣ ΜΕΤΑΒΟΛΩΝ ', A.BRANCH_NAME) BRANCH_NAME ---EE/DS FROM PEN_DEC_FACT_TYPES_INSTANCE, COM_ORG_BRANCHES A WHERE PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_INCR_SEQ_NO_SR = :P_DT_INCR_SEC_NO_SR ---I_DEC_INCR_SEQ_NO1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR ---I_DEC_UNIT1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR ---I_DEC_YEAR1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' ---I_DEC_DOC_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.TITLE_CODE = '99111' ---S_SPECIAL_FACT_TYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.DEC_FACT_TYPE_CODE = '99247' ---S_SPECIAL_FACT_SUBTYPE1 AND PEN_DEC_FACT_TYPES_INSTANCE.INS_INSURED_ID = :P_Insured_Id_IND ---I_INSURED_ID1 AND PEN_DEC_FACT_TYPES_INSTANCE.STATUS = '1' AND PEN_DEC_FACT_TYPES_INSTANCE.VALUE = A.BRANCH_CODE ORDER BY 1;
