      function CF_228Formula return Number is
V_AMT 			NUMBER;


begin

  IF NVL(:CF_EMLBR,0) != 0 THEN
  	V_AMT := :CF_EMLBR;
  ELSE
	  V_AMT :=  ROUND(:CF_224*:CF_229/100,2);
	END IF;	
  RETURN (V_AMT);
end;

      function CF_229Formula return Number is
CURSOR cur_INS_CLASS IS 

SELECT (DIKAIOD_LABOR_PRCN *100) DIKAIOD_LABOR_PRCN
FROM  PEN_CALC_NAT_LOWEST_DIKAIOD
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR
AND ACCOUNT_NO_DIKAIOD = :P_ACC_ACCOUNT_NO;

V_AMOUNT NUMBER;
begin

  OPEN cur_INS_CLASS;
  FETCH cur_INS_CLASS
  INTO V_AMOUNT;
  CLOSE cur_INS_CLASS;
  
  RETURN (ROUND(V_AMOUNT,2));
  END;

      function CF_224Formula return Number is
V_NUM	  NUMBER;
V_NUM_1	NUMBER;

CURSOR CUR_1 IS
SELECT LOWEST_LABOR_PENSION    
FROM  PEN_CALC_NATIONAL_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR; 


begin
  
IF NVL(:CF_EMLBR,0) != 0 THEN
	IF NVL(:CF_229,0) != 0 THEN
		V_NUM_1 := ROUND(:CF_EMLBR*100 / :CF_229,2);	  
	END IF;
ELSE

  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
	
END IF;	
  
  RETURN NVL(V_NUM_1,0);
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
end;

      function CF_230Formula return Char is

CURSOR CUR_LABOR_ACCIDENT IS
SELECT LABOR_ACCIDENT_FLG
FROM  PEN_CALC_NATIONAL_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR;

V_LABOR_ACCIDENT_FLG VARCHAR2(10);

CURSOR 	CUR_EMLBR IS
SELECT  '1'
FROM    PEN_QT_PER_BE_CC_PER_ACCOUNT C
WHERE   C.ACC_ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND     C.CP_CALCULATION_PARAMETER_CODE = 'OMLBR'
AND     C.STATUS = '1'
AND     C.CC_PER_BE_TYPE_PER_DECINS_UPD = '1';
BEGIN
	OPEN CUR_LABOR_ACCIDENT ;
	FETCH CUR_LABOR_ACCIDENT 
	INTO V_LABOR_ACCIDENT_FLG;
	CLOSE CUR_LABOR_ACCIDENT ;
	
	IF NVL(V_LABOR_ACCIDENT_FLG,0) = 0 THEN
		OPEN 	CUR_EMLBR;
		FETCH	CUR_EMLBR
		INTO	V_LABOR_ACCIDENT_FLG;
		CLOSE	CUR_EMLBR;
	END IF;
	
	
	RETURN (V_LABOR_ACCIDENT_FLG);

END;

      function CF_EMLBRFormula return Number is

V_AMT 			NUMBER;

CURSOR 	CUR_EMLBR IS
SELECT  C.AMOUNT
FROM    PEN_QT_PER_BE_CC_PER_ACCOUNT C
WHERE   C.ACC_ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND     C.CP_CALCULATION_PARAMETER_CODE = 'OMLBR'
AND     C.STATUS = '1'
AND     C.CC_PER_BE_TYPE_PER_DECINS_UPD = '1';

begin
		OPEN	 CUR_EMLBR;
		FETCH	  CUR_EMLBR
		INTO		V_AMT;
		CLOSE	 CUR_EMLBR; 	
  RETURN (V_AMT);
end;

